E   sqlalchemy.exc.InternalError: (psycopg2.InternalError) cannot drop operator -(jsonb,text) because it is required by the database system
E    [SQL: '-- http://schinckel.net/2014/09/29/adding-json%%28b%%29-operators-to-postgresql/
CREATE OR REPLACE FUNCTION "jsonb_subtract"(
  "json" jsonb,
  "key_to_remove" TEXT
)
  RETURNS jsonb
  LANGUAGE sql
  IMMUTABLE
  STRICT
AS $function$
SELECT CASE WHEN "json" ? "key_to_remove" THEN COALESCE(
  (SELECT ('{' || string_agg(to_json("key")::text || ':' || "value", ',') || '}')
     FROM jsonb_each("json")
    WHERE "key" <> "key_to_remove"),
